  ('social-worker-moex-02976', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '遊民問題（homelessness）是一個不可忽視的議題，下列那一項敘述正確？', '["遊民通常是由一群老年男性組成", "流落街頭的遊民中有不少是身心障礙、慢性病或藥物濫用者", "遊民指的就是住在街上的人", "遊民就是一群不工作的人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "42180c3b7589", "answer_pdf_sha1": "72c0e0eb6ff4", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
